module RefModule(A, B, Ci, S, Co);input A, B, Ci;
  output S, Co;

  wire AB, ACi, BCi;

  // Sum output: S = A XOR B XOR Ci
  assign S = A ^ B ^ Ci;

  // Carry output: Co = (A AND B) OR (B AND Ci) OR (A AND Ci)
  wire temp1_(A & B) | (B & Ci) = (A & B) | (B & Ci);
  wire temp2_(A & Ci) = (A & Ci);
  assign Co = temp1_(A & B) | (B & Ci) | temp2_(A & Ci);

endmodule
